// ============================================================================
// Auto-Tag on Merge to Main — Jenkins
// ============================================================================
// Generated by Agent: SETUP | Framework: mi-AI-Factory
// Platform: Jenkins
//
// Use as a standalone pipeline or include in your main Jenkinsfile.
// Calls scripts/auto-tag.sh on merge to main for SemVer tagging.
//
// Required: Jenkins credentials with Git push permissions.
//   Configure: Manage Jenkins → Credentials → git-push-credentials
// ============================================================================

pipeline {
    agent any

    triggers {
        // Triggered by webhook or SCM polling on main
        pollSCM('H/5 * * * *')
    }

    options {
        skipDefaultCheckout(true)
    }

    stages {
        stage('Checkout') {
            steps {
                checkout([
                    $class: 'GitSCM',
                    branches: [[name: 'main']],
                    extensions: [
                        [$class: 'CloneOption', depth: 0, shallow: false],
                        [$class: 'FetchTagsOption', fetchTags: true]
                    ],
                    userRemoteConfigs: scm?.userRemoteConfigs ?: [[url: env.GIT_URL ?: error('GIT_URL required in standalone mode')]]
                ])
            }
        }

        stage('Auto-Tag') {
            when {
                branch 'main'
                expression {
                    def msg = sh(script: 'git log -1 --pretty=format:"%s"', returnStdout: true).trim()
                    return msg.contains('Merge pull request') || msg.matches(/.*\(#\d+\).*/)
                }
            }
            steps {
                sshagent(credentials: ['git-push-credentials']) {
                    sh '''
                        chmod +x scripts/auto-tag.sh
                        OUTPUT=$(bash scripts/auto-tag.sh --apply --ci 2>&1)
                        echo "$OUTPUT"
                        NEW_TAG=$(echo "$OUTPUT" | grep -oP '(?<=TAG=)\\S+')
                        if [ -n "$NEW_TAG" ]; then
                            echo "✅ Tag $NEW_TAG created and pushed"
                        fi
                    '''
                }
            }
        }
    }

    post {
        success {
            echo '✅ Auto-tag pipeline completed'
        }
        failure {
            echo '❌ Auto-tag pipeline failed'
        }
    }
}
